let element = null;
let dotNetRef = null;
let timeoutMs = 0;
let timerId = null;
let isIdle = false;
let handler = null;

function resetTimer() {
    clearTimeout(timerId);

    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("OnActiveCallback");
    }

    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);
}

export function initialize(el, ref, timeout) {
    element = el;
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    handler = () => resetTimer();

    const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];
    events.forEach(evt => element.addEventListener(evt, handler, { passive: true }));

    // Start the initial idle timer
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);
}

export function dispose() {
    clearTimeout(timerId);

    if (element && handler) {
        const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];
        events.forEach(evt => element.removeEventListener(evt, handler));
    }

    element = null;
    dotNetRef = null;
    handler = null;
    timerId = null;
}

